import React, { useState, useEffect } from "react";
import { motion, AnimatePresence } from "motion/react";
import { ChevronLeft, ChevronRight, Play, BookOpen, Brain, Gamepad2, BarChart3, CheckCircle2, Download, FileArchive } from "lucide-react";
import pptxgen from "pptxgenjs";
import JSZip from "jszip";

// Import images for reliable Vite/Vercel handling
import img1 from "./assets/1.png";
import img2 from "./assets/2.png";
import img3 from "./assets/3.png";
import img4 from "./assets/4.png";
import img5 from "./assets/5.png";
import img6 from "./assets/6.png";

interface SlideProps {
  title?: string;
  children: React.ReactNode;
  index: number;
  gradient?: string;
}

const Slide = ({ title, children, gradient = "bg-slate-950" }: SlideProps) => (
  <div className={`flex flex-col h-full w-full p-8 md:p-16 ${gradient} transition-colors duration-1000`}>
    {title && (
      <motion.h2 
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        className="text-3xl md:text-5xl font-bold text-white mb-12 uppercase tracking-tight border-l-4 border-white/50 pl-6 drop-shadow-lg"
      >
        {title}
      </motion.h2>
    )}
    <div className="flex-1 overflow-y-auto custom-scrollbar">
      {children}
    </div>
  </div>
);

export default function App() {
  const [currentSlide, setCurrentSlide] = useState(0);

  const downloadPPTX = () => {
    const pres = new pptxgen();
    pres.layout = "LAYOUT_16x9";
    const itmoBlue = "004A99";
    const white = "FFFFFF";

    // Slide 0: Title
    let slide0 = pres.addSlide();
    slide0.background = { color: itmoBlue };
    slide0.addText("XV КОНГРЕСС МОЛОДЫХ УЧЕНЫХ ИТМО", { x: 0.5, y: 1.0, w: "90%", h: 1.5, fontSize: 44, bold: true, color: white, align: "center" });
    slide0.addText("ИНТЕРАКТИВНЫЕ ИГРЫ В ОБУЧЕНИИ РУССКОМУ ЯЗЫКУ КАК ИНОСТРАННОМУ КАК ИНСТРУМЕНТ ПОВЫШЕНИЯ РУССКОЯЗЫЧНОЙ КОММУНИКАТИВНОЙ КОМПЕТЕНЦИИ ИНОСТРАННЫХ СТУДЕНТОВ", { x: 0.5, y: 2.8, w: "90%", h: 1.5, fontSize: 20, color: white, align: "center", bold: true });
    slide0.addText("Эвида Х.В.И.Х., Халил М. (Университет ИТМО)", { x: 0.5, y: 4.5, w: "90%", h: 0.5, fontSize: 18, color: white, align: "center" });
    slide0.addText("Научный руководитель – канд. пед. наук, доцент Кондрашова Н.В.", { x: 0.5, y: 5.0, w: "90%", h: 0.5, fontSize: 16, color: white, align: "center", italic: true });

    // Slide 2: Introduction
    let slide2 = pres.addSlide();
    slide2.addText("ВВЕДЕНИЕ", { x: 0.5, y: 0.5, w: "90%", h: 0.8, fontSize: 32, bold: true, color: itmoBlue });
    slide2.addText("В современную цифровую эпоху игры стали мощным образовательным инструментом.", { x: 0.5, y: 1.5, w: "45%", h: 2.0, fontSize: 18 });
    slide2.addImage({ path: img1, x: 5.5, y: 1.5, w: 4.0, h: 3.0 });

    // Slide 4: Solution
    let slide4 = pres.addSlide();
    slide4.addText("ПОЧЕМУ ИГРЫ РАБОТАЮТ?", { x: 0.5, y: 0.5, w: "90%", h: 0.8, fontSize: 32, bold: true, color: itmoBlue });
    slide4.addImage({ path: img2, x: 5.5, y: 3.5, w: 4.0, h: 2.0 });

    // Slide 5: Game
    let slide5 = pres.addSlide();
    slide5.addText("ИГРА «ЯЗЫКОВЫЕ ДЕТЕКТИВЫ»", { x: 0.5, y: 0.5, w: "90%", h: 0.8, fontSize: 32, bold: true, color: itmoBlue });
    slide5.addImage({ path: img3, x: 5.5, y: 1.5, w: 4.0, h: 3.0 });

    // Slide 6: Mechanics
    let slide6 = pres.addSlide();
    slide6.addText("МЕХАНИЗМ ИГРЫ", { x: 0.5, y: 0.5, w: "90%", h: 0.8, fontSize: 32, bold: true, color: itmoBlue });
    slide6.addImage({ path: img2, x: 0.5, y: 1.5, w: 2.0, h: 1.5 });
    slide6.addImage({ path: img4, x: 2.8, y: 1.5, w: 2.0, h: 1.5 });
    slide6.addImage({ path: img5, x: 5.1, y: 1.5, w: 2.0, h: 1.5 });
    slide6.addImage({ path: img6, x: 7.4, y: 1.5, w: 2.0, h: 1.5 });

    // Slide 7: Results
    let slide7 = pres.addSlide();
    slide7.addText("РЕЗУЛЬТАТЫ ИССЛЕДОВАНИЯ", { x: 0.5, y: 0.5, w: "90%", h: 0.8, fontSize: 32, bold: true, color: itmoBlue });
    slide7.addImage({ path: img6, x: 0.5, y: 3.0, w: 4.5, h: 2.5 });

    // Slide 8: Conclusion
    let slide8 = pres.addSlide();
    slide8.addText("ВЫВОДЫ", { x: 0.5, y: 0.5, w: "90%", h: 0.8, fontSize: 32, bold: true, color: itmoBlue });
    slide8.addImage({ path: img5, x: 5.5, y: 1.5, w: 4.0, h: 3.0 });

    pres.writeFile({ fileName: "Presentation_ITMO_RKI.pptx" });
  };

  const downloadProjectZip = async () => {
    const zip = new JSZip();
    const files = [
      { path: "src/App.tsx", url: "/src/App.tsx" },
      { path: "src/main.tsx", url: "/src/main.tsx" },
      { path: "src/index.css", url: "/src/index.css" },
      { path: "index.html", url: "/index.html" },
      { path: "package.json", url: "/package.json" },
      { path: "vite.config.ts", url: "/vite.config.ts" },
      { path: "tsconfig.json", url: "/tsconfig.json" },
      { path: "src/assets/1.png", url: img1 },
      { path: "src/assets/2.png", url: img2 },
      { path: "src/assets/3.png", url: img3 },
      { path: "src/assets/4.png", url: img4 },
      { path: "src/assets/5.png", url: img5 },
      { path: "src/assets/6.png", url: img6 },
    ];

    for (const file of files) {
      try {
        const response = await fetch(file.url);
        const blob = await response.blob();
        zip.file(file.path, blob);
      } catch (error) {
        console.error(`Failed to fetch ${file.path}:`, error);
      }
    }

    const content = await zip.generateAsync({ type: "blob" });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(content);
    link.download = "itmo_presentation_project.zip";
    link.click();
  };

  const slides = [
    {
      type: "title",
      gradient: "itmo-gradient",
      content: (
        <div className="flex flex-col items-center justify-center h-full text-center rounded-3xl p-12 shadow-2xl relative overflow-hidden">
          <div className="absolute top-8 left-12 text-white font-bold text-2xl tracking-widest">ITMO</div>
          <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} transition={{ duration: 0.8 }} className="z-10">
            <h1 className="text-4xl md:text-6xl font-extrabold text-white mb-4 uppercase leading-tight drop-shadow-2xl">КМУ XV КОНГРЕСС МОЛОДЫХ УЧЕНЫХ ИТМО</h1>
            <div className="bg-white/20 backdrop-blur-md px-6 py-2 rounded-full inline-block mb-12 text-xl font-medium border border-white/30">6–10 апреля 2026</div>
            <div className="max-w-3xl mx-auto mt-8 space-y-4">
              <h2 className="text-xl md:text-2xl font-semibold text-white drop-shadow-md">ИНТЕРАКТИВНЫЕ ИГРЫ В ОБУЧЕНИИ РУССКОМУ ЯЗЫКУ КАК ИНОСТРАННОМУ...</h2>
              <p className="text-lg text-white/90 font-medium">Эвида Х.В.И.Х., Халил М. (Университет ИТМО)</p>
            </div>
          </motion.div>
        </div>
      )
    },
    {
      title: "ВВЕДЕНИЕ",
      gradient: "gradient-blue",
      content: (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-12 items-center">
          <div className="space-y-8 text-xl leading-relaxed">
            <p className="text-white font-medium drop-shadow-sm">В современную цифровую эпоху игры стали мощным образовательным инструментом.</p>
          </div>
          <div className="relative group">
            <img src={img1} alt="Game Environment" className="rounded-3xl shadow-2xl relative z-10 border-4 border-white/20" referrerPolicy="no-referrer" />
          </div>
        </div>
      )
    },
    {
      title: "ПОЧЕМУ ИГРЫ РАБОТАЮТ?",
      gradient: "gradient-purple",
      content: (
        <div className="space-y-8">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <motion.div whileHover={{ y: -10 }} className="p-8 bg-white/10 backdrop-blur-xl rounded-3xl border border-white/20 text-center shadow-2xl">
              <Brain className="w-16 h-16 text-white mx-auto mb-4 drop-shadow-lg" />
              <h4 className="font-black text-2xl mb-2">Когнитивное вовлечение</h4>
            </motion.div>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mt-8">
            <img src={img2} alt="Contextual Clues" className="rounded-3xl shadow-2xl border-2 border-white/20 h-48 object-cover w-full" referrerPolicy="no-referrer" />
          </div>
        </div>
      )
    },
    {
      title: "ИГРА «ЯЗЫКОВЫЕ ДЕТЕКТИВЫ»",
      gradient: "gradient-emerald",
      content: (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
          <div className="space-y-6">
            <h3 className="text-3xl font-black text-white drop-shadow-md">Концепция:</h3>
            <p className="text-xl text-white/90 font-medium">Интерактивный веб-квест с детективным приключенческим сюжетом.</p>
          </div>
          <div className="relative group">
            <img src={img3} alt="Game Start Screen" className="rounded-3xl shadow-2xl border-4 border-white/30 group-hover:scale-105 transition-transform duration-500" referrerPolicy="no-referrer" />
          </div>
        </div>
      )
    },
    {
      title: "МЕХАНИЗМ ИГРЫ",
      gradient: "gradient-amber",
      content: (
        <div className="space-y-8">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            {[
              { step: "1", title: "Прочитать", img: img2 },
              { step: "2", title: "Анализировать", img: img4 },
              { step: "3", title: "Составить", img: img5 },
              { step: "4", title: "Разгадать", img: img6 },
            ].map((m, i) => (
              <motion.div key={i} whileHover={{ scale: 1.05 }} className="bg-white/10 backdrop-blur-xl rounded-3xl border border-white/20 overflow-hidden shadow-2xl h-full flex flex-col">
                <img src={m.img} alt={m.title} className="w-full h-32 object-cover opacity-90" referrerPolicy="no-referrer" />
                <div className="p-6 relative flex-1">
                  <h4 className="text-2xl font-black mb-2 text-white">{m.title}</h4>
                </div>
              </motion.div>
            ))}
          </div>
        </div>
      )
    },
    {
      title: "РЕЗУЛЬТАТЫ ИССЛЕДОВАНИЯ",
      gradient: "gradient-indigo",
      content: (
        <div className="space-y-12">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="relative">
              <img src={img6} alt="Puzzle Result" className="rounded-3xl shadow-2xl border-4 border-white/20" referrerPolicy="no-referrer" />
            </div>
          </div>
        </div>
      )
    },
    {
      title: "ВЫВОДЫ",
      gradient: "gradient-emerald",
      content: (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-12 items-center">
          <div className="space-y-6 text-xl">
            <p className="font-bold text-white">Игры — эффективный инструмент для изучения РКИ взрослыми учащимися.</p>
          </div>
          <div className="relative">
            <img src={img5} alt="Game Clues" className="rounded-3xl shadow-2xl border-4 border-white/30 h-[500px] w-full object-cover" referrerPolicy="no-referrer" />
          </div>
        </div>
      )
    },
    {
      type: "thanks",
      gradient: "itmo-gradient",
      content: (
        <div className="flex flex-col items-center justify-center h-full text-center rounded-3xl p-12 shadow-2xl relative overflow-hidden">
          <motion.div initial={{ y: 20, opacity: 0 }} animate={{ y: 0, opacity: 1 }} transition={{ delay: 0.2 }} className="z-10">
            <h1 className="text-5xl md:text-8xl font-black text-white mb-8 uppercase tracking-tighter drop-shadow-2xl">СПАСИБО ЗА ВНИМАНИЕ!</h1>
            <div className="mt-12 space-y-4 bg-white/10 backdrop-blur-md p-8 rounded-3xl border border-white/20 inline-block">
              <p className="text-2xl font-black text-white">Эвида Х.В.И.Х., Халил М.</p>
              <p className="text-white/80 text-xl">nvkondrashova@itmo.ru</p>
            </div>
          </motion.div>
        </div>
      )
    }
  ];

  const nextSlide = () => { if (currentSlide < slides.length - 1) setCurrentSlide(prev => prev + 1); };
  const prevSlide = () => { if (currentSlide > 0) setCurrentSlide(prev => prev - 1); };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === "ArrowRight" || e.key === " ") nextSlide();
      if (e.key === "ArrowLeft") prevSlide();
    };
    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [currentSlide]);

  return (
    <div className="h-screen w-screen bg-slate-950 flex flex-col overflow-hidden font-sans selection:bg-white/30">
      <div className="h-2 w-full bg-slate-900 z-50">
        <motion.div className="h-full bg-white shadow-[0_0_15px_rgba(255,255,255,0.5)]" initial={{ width: "0%" }} animate={{ width: `${((currentSlide + 1) / slides.length) * 100}%` }} />
      </div>
      <main className="flex-1 relative overflow-hidden">
        <AnimatePresence mode="wait">
          <motion.div key={currentSlide} initial={{ opacity: 0, scale: 1.1 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 0.9 }} transition={{ duration: 0.5 }} className="h-full w-full">
            {slides[currentSlide].type === "title" || slides[currentSlide].type === "thanks" ? (
              <div className={`h-full w-full p-4 md:p-8 ${slides[currentSlide].gradient}`}>{slides[currentSlide].content}</div>
            ) : (
              <Slide index={currentSlide} title={slides[currentSlide].title} gradient={slides[currentSlide].gradient}>{slides[currentSlide].content}</Slide>
            )}
          </motion.div>
        </AnimatePresence>
      </main>
      <footer className="h-24 px-8 flex items-center justify-between bg-black/40 backdrop-blur-xl border-t border-white/10 z-50">
        <div className="flex items-center space-x-6">
          <div className="bg-white/10 px-4 py-2 rounded-full border border-white/20 text-white font-black text-lg shadow-xl">{String(currentSlide + 1).padStart(2, '0')} / {String(slides.length).padStart(2, '0')}</div>
        </div>
        <div className="flex items-center space-x-4">
          <button onClick={downloadProjectZip} className="flex items-center space-x-2 px-6 py-3 rounded-2xl bg-white/10 text-white font-black hover:bg-white/20 transition-all active:scale-95 shadow-2xl border border-white/10"><FileArchive className="w-6 h-6" /><span className="hidden lg:inline">ZIP</span></button>
          <button onClick={downloadPPTX} className="flex items-center space-x-2 px-6 py-3 rounded-2xl bg-white text-slate-900 font-black hover:bg-white/90 transition-all active:scale-95 shadow-2xl"><Download className="w-6 h-6" /><span className="hidden lg:inline">PPTX</span></button>
          <button onClick={prevSlide} disabled={currentSlide === 0} className="p-4 rounded-2xl bg-white/10 hover:bg-white/20 disabled:opacity-20 disabled:cursor-not-allowed transition-all active:scale-90 border border-white/10 shadow-2xl"><ChevronLeft className="w-8 h-8 text-white" /></button>
          <button onClick={nextSlide} disabled={currentSlide === slides.length - 1} className="p-4 rounded-2xl bg-white/10 hover:bg-white/20 disabled:opacity-20 disabled:cursor-not-allowed transition-all active:scale-90 border border-white/10 shadow-2xl"><ChevronRight className="w-8 h-8 text-white" /></button>
        </div>
      </footer>
    </div>
  );
}

